USE challenge_cup_energy;

-- =========================================================
-- 【重要】执行前先清空，再重新导入
-- mpc_results_final.csv → mpc_realtime_control (120 rows)
-- 说明：final 是 MPC 动态调控最终结果（含削峰填谷响应）
--       00时段稳定，01时段锅炉29.3→31.5MW削峰，02时段恢复
--   DELETE 会清空所有旧 MPC 数据（含 seed_demo_data 的 1 条样本）
-- =========================================================

DELETE FROM mpc_realtime_control WHERE control_date >= '2026-07-17';
DELETE FROM algorithm_task WHERE task_type = 'REALTIME_MPC';

INSERT INTO algorithm_task (
  id, task_type, status, progress, result_id, message, retry_count,
  algorithm_name, algorithm_version, result_file_name, algorithm_response_json,
  start_time, finish_time, deleted, remark
)
VALUES (
  5000000000000000002,
  'REALTIME_MPC',
  'SUCCESS',
  100,
  5000000000000000201,
  'mpc_results_final.csv 导入成功',
  0,
  'MPC_REALTIME_CONTROL',
  'v1.0',
  'mpc_results_final.csv',
  '{"description":"2-hour MPC final results, 1-min granularity, 120 time steps","avg_boiler_mw":27.90,"avg_turbine_mw":8.005,"total_grid_kwh":12.4500}',
  '2026-07-17 00:01:00',
  '2026-07-17 02:00:01',
  0,
  '算法组 mpc_results_final.csv'
)
ON DUPLICATE KEY UPDATE
  status = VALUES(status),
  progress = VALUES(progress),
  result_id = VALUES(result_id),
  message = VALUES(message),
  algorithm_response_json = VALUES(algorithm_response_json),
  finish_time = VALUES(finish_time),
  deleted = 0,
  remark = VALUES(remark);

